# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

//ReviewController.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using ReviewApp.Models; //Assumes you have a model named 'ProductReview' in your Models folder
using System.Data.Entity; 

namespace ReviewApp.Controllers
{
    public class ReviewController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();
        
        // GET: Reviews for a specific product
        public ActionResult Index(int id)
        {
            var reviews = db.ProductReviews.Where(r => r.ProductID == id).ToList();
            
            return View(reviews);
        }
        
    }
}